sys_script_include.script:
var LocationScript = Class.create();
LocationScript.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {



    getCityCountry: function() {

        gs.info('getCityCountry called the city ' + this.getParameter('sysparm_usersysid'));

        var userSysId = this.getParameter('sysparm_usersysid');
        var userGr = new GlideRecord('sys_user');
        if (userGr.get(userSysId)) {
            var city = userGr.location.city.toString();
            var country = userGr.location.country.toString();
            return city + ',' + country;
        }
        return '';



    },


    type: 'LocationScript'
});
